// FixedModelHeader.js - 언어/레벨/파트 선택 헤더 컴포넌트

import React from 'react';

const FixedModelHeader = ({
  selectedLanguage,
  selectedCourse,
  selectedLevel,
  selectedPart,
  languageConfig,
  mockTestData,
  onFilterChange,
  isLoading
}) => {

  // ===== 사용 가능한 옵션 가져오기 =====
  const getAvailableCourses = () => {
    if (!selectedLanguage) return [];
    return languageConfig[selectedLanguage]?.courses || [];
  };

  const getAvailableLevels = () => {
    if (!selectedLanguage || !selectedCourse) return [];
    
    // mockTestData에서 해당 언어의 테스트 타입 찾기
    const testType = getTestTypeByLanguage(selectedLanguage);
    if (!testType || !mockTestData[testType]) return [];
    
    // 실제 사용 가능한 레벨들 (mockTestData 기준)
    return ['Beginner', 'Intermediate', 'Advanced'].filter(level => {
      // 각 레벨에 실제 파트가 있는지 확인
      return mockTestData[testType].parts && mockTestData[testType].parts.length > 0;
    });
  };

  const getAvailableParts = () => {
    if (!selectedLanguage || !selectedCourse || !selectedLevel) return [];
    
    const testType = getTestTypeByLanguage(selectedLanguage);
    if (!testType || !mockTestData[testType]) return [];
    
    // mockTestData의 파트들을 그대로 사용
    return mockTestData[testType].parts.map((part, index) => ({
      id: index + 1,
      name: part.name,
      description: part.description,
      questions: part.questions
    }));
  };

  // ===== 언어에서 테스트 타입 매핑 =====
  const getTestTypeByLanguage = (language) => {
    const mapping = {
      'English': 'englishElite', // 또는 englishExpress
      'Korean': 'korean',
      'Japanese': 'japanese',
      'Chinese': 'chinese'
    };
    return mapping[language];
  };

  // ===== 렌더링 헬퍼 =====
  const availableCourses = getAvailableCourses();
  const availableLevels = getAvailableLevels();
  const availableParts = getAvailableParts();

  return (
    <div className="fixed-model-header">
      <div className="header-title">
        <h2>
          <span className="title-icon">🎛️</span>
          Select Training Parameters
        </h2>
        <p className="title-subtitle">
          Choose language, course, level, and part to start your focused practice session
        </p>
      </div>

      <div className="filter-grid">
        {/* 언어 선택 */}
        <div className="filter-group">
          <label className="filter-label">
            <span className="label-icon">🌍</span>
            Language
          </label>
          <div className="filter-options">
            {Object.entries(languageConfig).map(([key, config]) => (
              <button
                key={key}
                className={`filter-option ${selectedLanguage === key ? 'active' : ''}`}
                onClick={() => onFilterChange('language', key)}
                disabled={isLoading}
              >
                <span className="option-flag">{config.flag}</span>
                <span className="option-name">{config.name}</span>
              </button>
            ))}
          </div>
        </div>

        {/* 코스 선택 */}
        <div className="filter-group">
          <label className="filter-label">
            <span className="label-icon">📚</span>
            Course
          </label>
          <div className="filter-options">
            {availableCourses.length > 0 ? (
              availableCourses.map((course) => (
                <button
                  key={course}
                  className={`filter-option ${selectedCourse === course ? 'active' : ''}`}
                  onClick={() => onFilterChange('course', course)}
                  disabled={isLoading || !selectedLanguage}
                >
                  <span className="option-icon">
                    {course === 'Basic' && '🌱'}
                    {course === 'Expressor' && '🎭'}
                    {course === 'Elite' && '👑'}
                  </span>
                  <span className="option-name">{course}</span>
                </button>
              ))
            ) : (
              <div className="filter-placeholder">
                {selectedLanguage ? 'No courses available' : 'Select a language first'}
              </div>
            )}
          </div>
        </div>

        {/* 레벨 선택 */}
        <div className="filter-group">
          <label className="filter-label">
            <span className="label-icon">⭐</span>
            Level
          </label>
          <div className="filter-options">
            {availableLevels.length > 0 ? (
              availableLevels.map((level) => (
                <button
                  key={level}
                  className={`filter-option ${selectedLevel === level ? 'active' : ''}`}
                  onClick={() => onFilterChange('level', level)}
                  disabled={isLoading || !selectedCourse}
                >
                  <span className="option-icon">
                    {level === 'Beginner' && '🌱'}
                    {level === 'Intermediate' && '🌿'}
                    {level === 'Advanced' && '🌳'}
                  </span>
                  <span className="option-name">{level}</span>
                </button>
              ))
            ) : (
              <div className="filter-placeholder">
                {selectedCourse ? 'No levels available' : 'Select a course first'}
              </div>
            )}
          </div>
        </div>

        {/* 파트 선택 */}
        <div className="filter-group full-width">
          <label className="filter-label">
            <span className="label-icon">🎯</span>
            Part
          </label>
          <div className="filter-options parts-grid">
            {availableParts.length > 0 ? (
              availableParts.map((part) => (
                <button
                  key={part.id}
                  className={`filter-option part-option ${selectedPart === part.name ? 'active' : ''}`}
                  onClick={() => onFilterChange('part', part.name)}
                  disabled={isLoading || !selectedLevel}
                >
                  <div className="part-header">
                    <span className="part-number">Part {part.id}</span>
                    <span className="part-questions">{part.questions} questions</span>
                  </div>
                  <div className="part-name">{part.name}</div>
                  <div className="part-description">{part.description}</div>
                </button>
              ))
            ) : (
              <div className="filter-placeholder">
                {selectedLevel ? 'No parts available' : 'Select a level first'}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* 선택 요약 */}
      {selectedLanguage && selectedCourse && selectedLevel && selectedPart && (
        <div className="selection-summary">
          <div className="summary-content">
            <span className="summary-icon">✅</span>
            <span className="summary-text">
              Ready to train: <strong>{selectedLanguage}</strong> → 
              <strong>{selectedCourse}</strong> → 
              <strong>{selectedLevel}</strong> → 
              <strong>{selectedPart}</strong>
            </span>
          </div>
        </div>
      )}

      {/* 로딩 표시 */}
      {isLoading && (
        <div className="loading-indicator">
          <div className="loading-spinner"></div>
          <span>Loading questions...</span>
        </div>
      )}
    </div>
  );
};

export default FixedModelHeader;