// ===== FixedModelAnswerMode 연동 함수들 =====

// 언어별 테스트 타입 매핑
export const getTestTypeByLanguage = (language) => {
  const mapping = {
    'English': 'englishElite',
    'Korean': 'korean',
    'Japanese': 'japanese',
    'Chinese': 'chinese'
  };
  return mapping[language];
};

// 사용 가능한 코스 가져오기
export const getAvailableCourses = (language) => {
  if (!language || !FIXED_MODEL_CONFIG.SUPPORTED_LANGUAGES.includes(language)) {
    return [];
  }
  return FIXED_MODEL_CONFIG.SUPPORTED_COURSES;
};

// 사용 가능한 레벨 가져오기
export const getAvailableLevels = (language, course) => {
  if (!language || !course) return [];
  return FIXED_MODEL_CONFIG.SUPPORTED_LEVELS;
};

// 사용 가능한 파트 가져오기
export const getAvailableParts = (language) => {
  const testType = getTestTypeByLanguage(language);
  if (!testType || !mockTestData[testType]) return [];
  
  return mockTestData[testType].parts.map((part, index) => ({
    id: index + 1,
    name: part.name,
    description: part.description,
    questions: part.questions
  }));
};

