// FixedModelAnswerMode.js - 고정 모범답안 기반 훈련 모드 (완전한 풀버전)

import React, { useState, useEffect, useCallback } from 'react';
import FixedModelHeader from './FixedModelHeader';
import FixedModelCard from './FixedModelCard';
import AudioRecorder from './AudioRecorder';
import { fetchGoogleSheetData } from './fetchGoogleSheet';
import { 
  mockTestData, 
  languageData, 
  fixedModelConfig,
  getTestTypeByLanguage,
  getTestTypeByCourse,
  getAvailableCourses,
  getAvailableParts,
  validateTestSelection,
  getLanguageConfig,
  generateMockQuestions
} from './fixedModelConfig';
import './FixedModelAnswerMode.css';

const FixedModelAnswerMode = ({ onClose, selectedLanguage: initialLanguage }) => {
  // ===== 필터 상태 =====
  const [selectedLanguage, setSelectedLanguage] = useState(initialLanguage || 'English');
  const [selectedCourse, setSelectedCourse] = useState('Elite');
  const [selectedLevel, setSelectedLevel] = useState('Intermediate');
  const [selectedPart, setSelectedPart] = useState('');

  // ===== 데이터 상태 =====
  const [questions, setQuestions] = useState([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [dataSource, setDataSource] = useState(''); // 'sheets' or 'mock'

  // ===== 훈련 상태 =====
  const [isTrainingActive, setIsTrainingActive] = useState(false);
  const [showModelAnswer, setShowModelAnswer] = useState(false);
  const [userRecording, setUserRecording] = useState(null);
  const [currentStep, setCurrentStep] = useState('selection'); // 'selection', 'training'

  // ===== 오디오 상태 =====
  const [isQuestionPlaying, setIsQuestionPlaying] = useState(false);
  const [speechSynthesis, setSpeechSynthesis] = useState(null);

  // ===== 통계 상태 =====
  const [sessionStats, setSessionStats] = useState({
    totalQuestions: 0,
    completedQuestions: 0,
    viewedModelAnswers: 0,
    startTime: null,
    currentStreak: 0,
    bestStreak: 0
  });

  // ===== 음성 합성 초기화 =====
  useEffect(() => {
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      setSpeechSynthesis(window.speechSynthesis);
    }
  }, []);

  // ===== 질문 음성 재생 =====
  const speakQuestion = useCallback((text) => {
    if (!speechSynthesis || !text) return;

    // 기존 음성 중지
    speechSynthesis.cancel();
    setIsQuestionPlaying(true);

    const utterance = new SpeechSynthesisUtterance(text);
    const langCode = languageData[selectedLanguage]?.code || 'en-US';
    
    utterance.lang = langCode;
    utterance.rate = 0.9;
    utterance.pitch = 1.0;
    utterance.volume = 0.8;

    // 적절한 음성 선택
    const voices = speechSynthesis.getVoices();
    const preferredVoice = voices.find(voice => voice.lang.includes(langCode));
    if (preferredVoice) {
      utterance.voice = preferredVoice;
    }

    utterance.onend = () => {
      setIsQuestionPlaying(false);
    };

    utterance.onerror = () => {
      setIsQuestionPlaying(false);
      console.error('Speech synthesis error');
    };

    speechSynthesis.speak(utterance);
  }, [speechSynthesis, selectedLanguage]);

  // ===== 음성 중지 =====
  const stopSpeech = useCallback(() => {
    if (speechSynthesis) {
      speechSynthesis.cancel();
      setIsQuestionPlaying(false);
    }
  }, [speechSynthesis]);

  // ===== 질문 데이터 로드 =====
  const loadQuestions = useCallback(async () => {
    if (!selectedLanguage || !selectedCourse || !selectedLevel || !selectedPart) {
      console.log('⚠️ Missing required filters');
      return;
    }

    // 선택 유효성 검사
    const validation = validateTestSelection(selectedLanguage, selectedCourse, selectedLevel, selectedPart);
    if (!validation.isValid) {
      setError(`Selection Error: ${validation.errors.join(', ')}`);
      console.error('Validation failed:', validation.errors);
      return;
    }

    setIsLoading(true);
    setError('');
    setDataSource('');

    try {
      console.log('🔄 Attempting to load from Google Sheets...');
      
      // Google Sheets에서 데이터 fetch 시도
      const sheetData = await fetchGoogleSheetData({
        useCache: true,
        useAPI: false
      });
      
      console.log(`📊 Retrieved ${sheetData.length} total records from sheets`);
      
      // 필터링된 질문들 추출
      const filteredQuestions = sheetData.filter(item => {
        const matches = (
          item.language === selectedLanguage &&
          item.course === selectedCourse &&
          item.level === selectedLevel &&
          item.part === selectedPart &&
          item.question && 
          item.question.trim() !== ''
        );
        
        if (matches) {
          console.log('✅ Matched question:', item.question.substring(0, 50) + '...');
        }
        
        return matches;
      });

      let finalQuestions = [];

      if (filteredQuestions.length === 0) {
        console.log('⚠️ No matching questions from sheets, generating mock data');
        finalQuestions = generateMockQuestions(selectedLanguage, selectedCourse, selectedPart, selectedLevel);
        setDataSource('mock');
      } else {
        console.log(`✅ Found ${filteredQuestions.length} matching questions from sheets`);
        // 질문 셔플링 (설정에 따라)
        finalQuestions = fixedModelConfig.SHUFFLE_QUESTIONS ? 
          [...filteredQuestions].sort(() => Math.random() - 0.5) : 
          filteredQuestions;
        setDataSource('sheets');
      }

      // 최대 질문 수 제한
      if (finalQuestions.length > fixedModelConfig.MAX_QUESTIONS_PER_SESSION) {
        finalQuestions = finalQuestions.slice(0, fixedModelConfig.MAX_QUESTIONS_PER_SESSION);
        console.log(`✂️ Limited to ${fixedModelConfig.MAX_QUESTIONS_PER_SESSION} questions`);
      }

      setQuestions(finalQuestions);
      setCurrentQuestionIndex(0);
      setShowModelAnswer(false);
      setUserRecording(null);
      
      // 세션 통계 초기화
      setSessionStats({
        totalQuestions: finalQuestions.length,
        completedQuestions: 0,
        viewedModelAnswers: 0,
        startTime: Date.now(),
        currentStreak: 0,
        bestStreak: 0
      });

      console.log(`🎯 Successfully loaded ${finalQuestions.length} questions for training`);
      
    } catch (err) {
      console.error('❌ Failed to load from sheets:', err);
      
      // 폴백: Mock 데이터 사용
      console.log('🔄 Falling back to mock data generation...');
      try {
        const mockQuestions = generateMockQuestions(selectedLanguage, selectedCourse, selectedPart, selectedLevel);
        setQuestions(mockQuestions);
        setDataSource('mock');
        
        setSessionStats({
          totalQuestions: mockQuestions.length,
          completedQuestions: 0,
          viewedModelAnswers: 0,
          startTime: Date.now(),
          currentStreak: 0,
          bestStreak: 0
        });
        
        console.log(`✅ Generated ${mockQuestions.length} mock questions as fallback`);
        setError(''); // 에러 클리어 (mock 데이터로 성공했으므로)
      } catch (mockErr) {
        console.error('❌ Mock data generation also failed:', mockErr);
        setError('Failed to load questions. Please check your selection and try again.');
        setDataSource('');
      }
    } finally {
      setIsLoading(false);
    }
  }, [selectedLanguage, selectedCourse, selectedLevel, selectedPart]);

  // ===== 필터 변경 처리 =====
  const handleFilterChange = useCallback((filterType, value) => {
    console.log(`🔧 Filter changed: ${filterType} = ${value}`);
    
    // 음성 중지
    stopSpeech();
    
    switch (filterType) {
      case 'language':
        setSelectedLanguage(value);
        // 언어 변경 시 첫 번째 사용 가능한 코스로 설정
        const availableCourses = getAvailableCourses(value);
        const defaultCourse = availableCourses.includes('Elite') ? 'Elite' : availableCourses[0] || 'Basic';
        setSelectedCourse(defaultCourse);
        setSelectedLevel('Intermediate');
        setSelectedPart('');
        break;
      case 'course':
        setSelectedCourse(value);
        setSelectedLevel('Intermediate');
        setSelectedPart('');
        break;
      case 'level':
        setSelectedLevel(value);
        setSelectedPart('');
        break;
      case 'part':
        setSelectedPart(value);
        break;
    }
    
    // 상태 초기화
    setQuestions([]);
    setCurrentQuestionIndex(0);
    setIsTrainingActive(false);
    setCurrentStep('selection');
    setError('');
    setDataSource('');
    setShowModelAnswer(false);
    setUserRecording(null);
  }, [stopSpeech]);

  // ===== 훈련 시작 =====
  const startTraining = useCallback(async () => {
    console.log('🚀 Starting training session...');
    
    // 먼저 현재 선택사항 검증
    if (!selectedLanguage || !selectedCourse || !selectedLevel || !selectedPart) {
      setError('Please select all required filters before starting.');
      return;
    }

    stopSpeech(); // 기존 음성 중지
    
    await loadQuestions();
    setIsTrainingActive(true);
    setCurrentStep('training');
    
    // 첫 번째 질문 자동 재생 (설정에 따라)
    setTimeout(() => {
      if (fixedModelConfig.AUTO_PLAY_QUESTION && questions.length > 0) {
        speakQuestion(questions[0]?.question);
      }
    }, 1000);
  }, [loadQuestions, selectedLanguage, selectedCourse, selectedLevel, selectedPart, stopSpeech, speakQuestion, questions]);

  // ===== 다음 질문 =====
  const nextQuestion = useCallback(() => {
    if (currentQuestionIndex < questions.length - 1) {
      stopSpeech(); // 현재 음성 중지
      
      setCurrentQuestionIndex(currentQuestionIndex + 1);
      setShowModelAnswer(false);
      setUserRecording(null);
      
      // 완료된 질문 수 업데이트
      setSessionStats(prev => {
        const newCompleted = prev.completedQuestions + 1;
        const newStreak = prev.currentStreak + 1;
        const newBestStreak = Math.max(prev.bestStreak, newStreak);
        
        return {
          ...prev,
          completedQuestions: newCompleted,
          currentStreak: newStreak,
          bestStreak: newBestStreak
        };
      });
      
      // 다음 질문 자동 재생
      setTimeout(() => {
        if (fixedModelConfig.AUTO_PLAY_QUESTION) {
          speakQuestion(questions[currentQuestionIndex + 1]?.question);
        }
      }, 500);
    }
  }, [currentQuestionIndex, questions.length, stopSpeech, speakQuestion, questions]);

  // ===== 이전 질문 =====
  const prevQuestion = useCallback(() => {
    if (currentQuestionIndex > 0) {
      stopSpeech(); // 현재 음성 중지
      
      setCurrentQuestionIndex(currentQuestionIndex - 1);
      setShowModelAnswer(false);
      setUserRecording(null);
      
      // 이전 질문 자동 재생
      setTimeout(() => {
        if (fixedModelConfig.AUTO_PLAY_QUESTION) {
          speakQuestion(questions[currentQuestionIndex - 1]?.question);
        }
      }, 500);
    }
  }, [currentQuestionIndex, stopSpeech, speakQuestion, questions]);

  // ===== 모범답안 토글 =====
  const toggleModelAnswer = useCallback(() => {
    if (!fixedModelConfig.ENABLE_MODEL_ANSWER_TOGGLE) {
      console.log('Model answer toggle is disabled');
      return;
    }

    if (!showModelAnswer) {
      setSessionStats(prev => ({
        ...prev,
        viewedModelAnswers: prev.viewedModelAnswers + 1
      }));
    }
    setShowModelAnswer(!showModelAnswer);
  }, [showModelAnswer]);

  // ===== 훈련 종료 =====
  const exitTraining = useCallback(() => {
    console.log('🏁 Exiting training session...');
    
    stopSpeech(); // 모든 음성 중지
    
    setIsTrainingActive(false);
    setCurrentStep('selection');
    setShowModelAnswer(false);
    setUserRecording(null);
    setCurrentQuestionIndex(0);
    setError('');
    
    // 세션 통계 로깅
    const duration = sessionStats.startTime ? Date.now() - sessionStats.startTime : 0;
    console.log('📊 Session Stats:', {
      duration: Math.round(duration / 1000) + 's',
      completed: sessionStats.completedQuestions,
      total: sessionStats.totalQuestions,
      modelAnswersViewed: sessionStats.viewedModelAnswers,
      bestStreak: sessionStats.bestStreak
    });
  }, [stopSpeech, sessionStats]);

  // ===== 음성 녹음 완료 처리 =====
  const handleRecordingComplete = useCallback((recordingData) => {
    setUserRecording(recordingData);
    console.log('✅ Recording completed:', {
      duration: recordingData.duration,
      transcript: recordingData.transcript?.substring(0, 50) + '...',
      confidence: recordingData.confidence
    });
    
    // 녹음 완료 시 현재 streak 증가
    setSessionStats(prev => ({
      ...prev,
      currentStreak: prev.currentStreak + 1
    }));
  }, []);

  // ===== 효과: 초기 언어 설정 =====
  useEffect(() => {
    if (initialLanguage && languageData[initialLanguage]) {
      console.log(`🌍 Setting initial language: ${initialLanguage}`);
      setSelectedLanguage(initialLanguage);
      const availableCourses = getAvailableCourses(initialLanguage);
      const defaultCourse = availableCourses.includes('Elite') ? 'Elite' : availableCourses[0] || 'Basic';
      setSelectedCourse(defaultCourse);
    }
  }, [initialLanguage]);

  // ===== 효과: 컴포넌트 언마운트 시 정리 =====
  useEffect(() => {
    return () => {
      console.log('🧹 Cleaning up FixedModelAnswerMode...');
      stopSpeech();
    };
  }, [stopSpeech]);

  // ===== 현재 질문 및 진행률 계산 =====
  const currentQuestion = questions[currentQuestionIndex];
  const progress = questions.length > 0 ? ((currentQuestionIndex + 1) / questions.length) * 100 : 0;
  const canShowModelAnswer = fixedModelConfig.ENABLE_MODEL_ANSWER_TOGGLE && 
    currentQuestion?.show_model_answer === 'yes';

  // ===== 렌더링 =====
  return (
    <div className="fixed-model-answer-mode">
      {/* 헤더 */}
      <div className="fixed-mode-header">
        <div className="header-content">
          <div className="brand-section">
            <h1 className="mode-title">
              <span className="title-icon">🎯</span>
              Fixed Model Answer Training
            </h1>
            <p className="mode-subtitle">
              Practice with pre-made model answers • GPT-free training
              {dataSource && (
                <span className="data-source-badge">
                  • Data: {dataSource === 'sheets' ? '📊 Google Sheets' : '🎭 Mock Data'}
                </span>
              )}
            </p>
          </div>
          <button onClick={onClose} className="close-button" title="Close training mode">
            <span className="close-icon">✕</span>
          </button>
        </div>
        
        {/* 진행률 표시 (훈련 중일 때만) */}
        {isTrainingActive && questions.length > 0 && fixedModelConfig.SHOW_PROGRESS_BAR && (
          <div className="training-progress">
            <div className="progress-info">
              <span className="progress-text">
                Question {currentQuestionIndex + 1} of {questions.length}
              </span>
              <span className="progress-percentage">{Math.round(progress)}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ width: `${progress}%` }}
                aria-label={`Progress: ${Math.round(progress)}%`}
              ></div>
            </div>
          </div>
        )}
      </div>

      {/* 메인 콘텐츠 */}
      <div className="fixed-mode-main">
        {currentStep === 'selection' && (
          <>
            {/* 필터 헤더 */}
            <FixedModelHeader
              selectedLanguage={selectedLanguage}
              selectedCourse={selectedCourse}
              selectedLevel={selectedLevel}
              selectedPart={selectedPart}
              languageConfig={getLanguageConfig()}
              mockTestData={mockTestData}
              onFilterChange={handleFilterChange}
              isLoading={isLoading}
            />

            {/* 시작 섹션 */}
            <div className="start-section">
              {error && (
                <div className="error-message">
                  <span className="error-icon">⚠️</span>
                  <span>{error}</span>
                </div>
              )}

              {selectedLanguage && selectedCourse && selectedLevel && selectedPart && !error && (
                <div className="ready-to-start">
                  <div className="start-info">
                    <h3>🚀 Ready to Start Training!</h3>
                    <p>
                      Training configuration: <strong>{selectedLanguage} {selectedCourse} {selectedLevel} - {selectedPart}</strong>
                      {questions.length > 0 && (
                        <span> • {questions.length} question{questions.length !== 1 ? 's' : ''} loaded</span>
                      )}
                    </p>
                    {dataSource && (
                      <p className="data-source-info">
                        Data source: {dataSource === 'sheets' ? '📊 Google Sheets' : '🎭 Generated Mock Data'}
                      </p>
                    )}
                  </div>
                  <button 
                    className="start-training-button"
                    onClick={startTraining}
                    disabled={isLoading}
                    aria-label="Start training session"
                  >
                    <span className="button-icon">▶️</span>
                    {isLoading ? 'Loading Questions...' : 'Start Training Session'}
                  </button>
                </div>
              )}

              {!selectedPart && !isLoading && (
                <div className="no-questions">
                  <div className="no-questions-icon">📝</div>
                  <h3>Complete Your Selection</h3>
                  <p>Please select all training parameters: Language, Course, Level, and Part.</p>
                </div>
              )}
            </div>
          </>
        )}

        {currentStep === 'training' && (
          <div className="training-session">
            {currentQuestion ? (
              <>
                {/* 질문 카드 */}
                <FixedModelCard
                  question={currentQuestion}
                  questionNumber={currentQuestionIndex + 1}
                  totalQuestions={questions.length}
                  showModelAnswer={showModelAnswer}
                  canShowModelAnswer={canShowModelAnswer}
                  onToggleModelAnswer={toggleModelAnswer}
                  selectedLanguage={selectedLanguage}
                  isQuestionPlaying={isQuestionPlaying}
                  onPlayQuestion={() => speakQuestion(currentQuestion.question)}
                  onStopQuestion={stopSpeech}
                />

                {/* 오디오 레코더 */}
                <AudioRecorder
                  questionText={currentQuestion.question}
                  isActive={isTrainingActive}
                  onRecordingComplete={handleRecordingComplete}
                  language={languageData[selectedLanguage]?.code || 'en-US'}
                  maxRecordingTime={fixedModelConfig.MAX_RECORDING_TIME || 180}
                />
              </>
            ) : (
              <div className="no-questions">
                <div className="no-questions-icon">❌</div>
                <h3>No Questions Available</h3>
                <p>No questions could be loaded for the selected criteria. Please try different settings.</p>
                <button 
                  className="nav-button secondary"
                  onClick={exitTraining}
                >
                  Back to Selection
                </button>
              </div>
            )}

            {/* 네비게이션 */}
            <div className="training-navigation">
              <div className="nav-buttons">
                <button 
                  className="nav-button secondary"
                  onClick={exitTraining}
                  aria-label="Return to selection screen"
                >
                  <span className="button-icon">←</span>
                  Back to Selection
                </button>

                {questions.length > 1 && (
                  <div className="question-nav">
                    <button 
                      className="nav-button"
                      onClick={prevQuestion}
                      disabled={currentQuestionIndex === 0}
                      aria-label="Previous question"
                    >
                      <span className="button-icon">⬅️</span>
                      Previous
                    </button>
                    
                    <span className="nav-info" aria-live="polite">
                      {currentQuestionIndex + 1} / {questions.length}
                    </span>
                    
                    <button 
                      className="nav-button"
                      onClick={nextQuestion}
                      disabled={currentQuestionIndex === questions.length - 1}
                      aria-label="Next question"
                    >
                      Next
                      <span className="button-icon">➡️</span>
                    </button>
                  </div>
                )}
              </div>

              {/* 향상된 세션 통계 */}
              <div className="session-stats">
                <div className="stat-item">
                  <span className="stat-label">Questions:</span>
                  <span className="stat-value">{questions.length}</span>
                </div>
                <div className="stat-item">
                  <span className="stat-label">Completed:</span>
                  <span className="stat-value">{sessionStats.completedQuestions}</span>
                </div>
                <div className="stat-item">
                  <span className="stat-label">Model Answers:</span>
                  <span className="stat-value">{sessionStats.viewedModelAnswers}</span>
                </div>
                <div className="stat-item">
                  <span className="stat-label">Streak:</span>
                  <span className="stat-value">{sessionStats.currentStreak}</span>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* 로딩 오버레이 */}
        {isLoading && (
          <div className="loading-overlay" role="status" aria-label="Loading questions">
            <div className="loading-spinner"></div>
            <p>Loading questions from {dataSource || ''}...</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default FixedModelAnswerMode;