// appHooks.js - 축소된 버전 (5개 모드 제거)
import { useState, useCallback, useRef } from 'react';
import { createSpeechRecognition } from './AudioRecognition';
import { API_ENDPOINTS, STORAGE_KEYS } from './appData';

// ===== 앱 상태 관리 훅 =====
export const useAppState = () => {
  // 1. 기본 & 설정 상태
  const [selectedLanguage, setSelectedLanguage] = useState('english');
  const [apiKey, setApiKey] = useState(localStorage.getItem(STORAGE_KEYS.API_KEY) || '');
  const [availableVoices, setAvailableVoices] = useState([]);
  const [selectedVoiceType, setSelectedVoiceType] = useState('adult');
  const [selectedVoiceGender, setSelectedVoiceGender] = useState('female');
  const [questionPlaybackRate, setQuestionPlaybackRate] = useState(1.0);
  const [showTutorMode, setShowTutorMode] = useState(false);
  const [feedbackLanguage, setFeedbackLanguage] = useState('english');
  
  // 2. 주요 화면 & 모드 상태
  const [chatMode, setChatMode] = useState(false);
  const [showFixedModelMode, setShowFixedModelMode] = useState(false);
  
  // 3. 질문 & 답변 상태
  const [audioUrl, setAudioUrl] = useState('');
  const [audioBlob, setAudioBlob] = useState(null);
  const [isRecording, setIsRecording] = useState(false);
  const [transcript, setTranscript] = useState('');
  
  // 4. 채팅 튜터 상태
  const [conversationEnded, setConversationEnded] = useState(false);
  const [chatMessages, setChatMessages] = useState([]);
  const [chatInput, setChatInput] = useState('');
  const [isChatProcessing, setIsChatProcessing] = useState(false);
  const [chatLanguage, setChatLanguage] = useState('english');
  const [scenarioType, setScenarioType] = useState('restaurant');
  const [difficultyLevel, setDifficultyLevel] = useState('beginner');
  const [chatPlaybackRate, setChatPlaybackRate] = useState(1.0);
  const [chatTranslationLanguage, setChatTranslationLanguage] = useState('english');
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [customScenario, setCustomScenario] = useState('');
  const [showCustomScenarioModal, setShowCustomScenarioModal] = useState(false);

  return {
    // 기본 설정 상태
    selectedLanguage, setSelectedLanguage,
    apiKey, setApiKey,
    availableVoices, setAvailableVoices,
    selectedVoiceType, setSelectedVoiceType,
    selectedVoiceGender, setSelectedVoiceGender,
    questionPlaybackRate, setQuestionPlaybackRate,
    showTutorMode, setShowTutorMode,
    feedbackLanguage, setFeedbackLanguage,
    
    // 모드 상태
    chatMode, setChatMode,
    showFixedModelMode, setShowFixedModelMode,
    
    // 질문 및 답변 상태
    audioUrl, setAudioUrl,
    audioBlob, setAudioBlob,
    isRecording, setIsRecording,
    transcript, setTranscript,
    
    // 채팅 상태
    conversationEnded, setConversationEnded,
    chatMessages, setChatMessages,
    chatInput, setChatInput,
    isChatProcessing, setIsChatProcessing,
    chatLanguage, setChatLanguage,
    scenarioType, setScenarioType,
    difficultyLevel, setDifficultyLevel,
    chatPlaybackRate, setChatPlaybackRate,
    chatTranslationLanguage, setChatTranslationLanguage,
    isAiSpeaking, setIsAiSpeaking,
    customScenario, setCustomScenario,
    showCustomScenarioModal, setShowCustomScenarioModal
  };
};

// ===== 오디오 제어 훅 =====
export const useAudioControls = ({
  availableVoices,
  selectedLanguage,
  selectedVoiceGender,
  selectedVoiceType,
  questionPlaybackRate,
  chatLanguage,
  chatPlaybackRate,
  recognitionRef,
  mediaRecorderRef,
  audioChunksRef,
  setIsRecording,
  setTranscript,
  setAudioBlob,
  setAudioUrl,
  setIsAiSpeaking,
  isRecording 
}) => {
  // 최적 음성 선택
  const getEnhancedVoice = useCallback(() => {
    const voices = availableVoices.length > 0 ? 
      availableVoices : 
      window.speechSynthesis.getVoices();
    
    let voicePool = [];
    const currentLang = selectedLanguage || 'en-US';
    
    if (selectedVoiceType === 'adult') {
      if (selectedVoiceGender === 'female') {
        voicePool = voices.filter(v => 
          v.lang.includes(currentLang) && 
          (v.name.includes('Female') || v.name.includes('female') || v.name.toLowerCase().includes('woman'))
        );
      } else {
        voicePool = voices.filter(v => 
          v.lang.includes(currentLang) && 
          (v.name.includes('Male') || v.name.includes('male') || v.name.toLowerCase().includes('man'))
        );
      }
    } else {
      if (selectedVoiceGender === 'female') {
        voicePool = voices.filter(v => 
          v.lang.includes(currentLang) && 
          (v.name.includes('Kid') || v.name.includes('Child') || v.name.includes('Young'))
        );
        if (voicePool.length === 0) {
          voicePool = voices.filter(v => 
            v.lang.includes(currentLang) && 
            (v.name.includes('Female') || v.name.includes('female'))
          );
        }
      } else {
        voicePool = voices.filter(v => 
          v.lang.includes(currentLang) && 
          (v.name.includes('Boy') || v.name.includes('Kid') || v.name.includes('Child'))
        );
        if (voicePool.length === 0) {
          voicePool = voices.filter(v => 
            v.lang.includes(currentLang) && 
            (v.name.includes('Male') || v.name.includes('male'))
          );
        }
      }
    }
    
    if (voicePool.length === 0) {
      voicePool = voices.filter(v => v.lang.includes(currentLang));
    }
    
    return voicePool.length > 0 ? voicePool[0] : voices[0];
  }, [availableVoices, selectedLanguage, selectedVoiceGender, selectedVoiceType]);

  // 고급 음성 합성
  const speakWithEnhancedVoice = useCallback((text, rate = questionPlaybackRate, isChat = false) => {
    if (window.speechSynthesis.speaking) {
      window.speechSynthesis.cancel();
    }
    
    if (isChat) {
      setIsAiSpeaking(true);
    }
    
    const currentLanguage = isChat ? chatLanguage : selectedLanguage;
    const currentLangCode = currentLanguage || 'en-US';
    
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = currentLangCode;
    utterance.rate = rate;
    utterance.pitch = selectedVoiceType === 'child' ? 1.2 : 1.0;
    utterance.volume = 1.0;
    
    const enhancedVoice = getEnhancedVoice();
    if (enhancedVoice) {
      utterance.voice = enhancedVoice;
    }
    
    utterance.onend = () => {
      if (isChat) {
        setIsAiSpeaking(false);
      }
    };
    
    utterance.onerror = (error) => {
      console.error("음성 합성 오류:", error);
      if (isChat) {
        setIsAiSpeaking(false);
      }
    };
    
    window.speechSynthesis.speak(utterance);
  }, [questionPlaybackRate, getEnhancedVoice, selectedVoiceType, chatLanguage, selectedLanguage, setIsAiSpeaking]);

  // 질문 재생
  const speakQuestion = useCallback((text) => {
    speakWithEnhancedVoice(text);
  }, [speakWithEnhancedVoice]);

  // 음성 중지
  const stopSpeech = useCallback(() => {
    window.speechSynthesis.cancel();
    setIsAiSpeaking(false);
  }, [setIsAiSpeaking]);

  // 녹음 시작
  const startRecording = useCallback(async () => {
    try {
      if (isRecording) {
        stopRecording();
      }
      
      setAudioUrl('');
      setAudioBlob(null);
      setTranscript('');

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorderRef.current = new MediaRecorder(stream);
      audioChunksRef.current = [];

      if (recognitionRef.current) {
        try {
          recognitionRef.current.stop();
        } catch (e) {
          console.log('인식기 정리 중 오류 (무시 가능)', e);
        }
        
        recognitionRef.current.onresult = null;
        recognitionRef.current.onend = null;
        recognitionRef.current.onerror = null;
      }

      recognitionRef.current = createSpeechRecognition(
        selectedLanguage || 'en-US',
        (newTranscript) => setTranscript(newTranscript),
        setIsRecording
      );
      
      try {
        recognitionRef.current.start();
      } catch (error) {
        console.error('음성 인식 시작 오류:', error);
        alert("음성 인식을 시작할 수 없습니다. 브라우저를 새로고침하고 다시 시도해보세요.");
      }

      mediaRecorderRef.current.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorderRef.current.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        setAudioBlob(audioBlob);
        const audioUrl = URL.createObjectURL(audioBlob);
        setAudioUrl(audioUrl);
      };

      mediaRecorderRef.current.start(100);
      setIsRecording(true);
    } catch (err) {
      console.error("Recording error:", err);
      alert("마이크에 접근할 수 없습니다. 마이크 권한을 확인해주세요.");
    }
  }, [recognitionRef, mediaRecorderRef, audioChunksRef, selectedLanguage, setIsRecording, setTranscript, setAudioBlob, setAudioUrl, isRecording]);

  // 녹음 중지
  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
      
      if (mediaRecorderRef.current.stream) {
        mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      }
    }
    
    if (recognitionRef.current) {
      try {
        recognitionRef.current.stop();
      } catch (error) {
        console.error('음성 인식 중지 오류:', error);
      }
    }
    
    setIsRecording(false);
  }, [mediaRecorderRef, recognitionRef, setIsRecording]);

  return {
    getEnhancedVoice,
    speakWithEnhancedVoice,
    speakQuestion,
    stopSpeech,
    startRecording,
    stopRecording
  };
};

// ===== 채팅 기능 훅 =====
export const useChatFunctions = ({
  apiKey,
  chatLanguage,
  chatMessages,
  setChatMessages,
  chatInput,
  setChatInput,
  isChatProcessing,
  setIsChatProcessing,
  difficultyLevel,
  scenarioType,
  customScenario,
  setConversationEnded,
  feedbackLanguage,
  chatPlaybackRate,
  speakWithEnhancedVoice,
  stopSpeech
}) => {
  // 채팅 컨텍스트 구축
  const buildChatContext = useCallback(() => {
    const selectedLangName = chatLanguage || 'English';
    
    let systemMessage = {
      role: 'system',
      content: `You are a professional ${selectedLangName} language tutor.
      Help the learner practice conversation in ${selectedLangName}.
      Follow these guidelines:
      
      1. Respond in ${selectedLangName} (except when the learner explicitly asks for explanations in their native language).
      2. Keep responses relatively concise and conversational.
      3. When the learner makes grammar or vocabulary errors, gently correct them by incorporating the correct expressions.
      4. Adjust language difficulty to the learner's level - avoid complex vocabulary or grammar for beginners.
      5. Ask follow-up questions to keep the conversation flowing.
      6. Provide cultural context when appropriate.
      7. Be patient, encouraging and friendly.`
    };

    if (scenarioType) {
      if (scenarioType === 'custom' && customScenario) {
        systemMessage.content += `\n\nCustom Scenario: ${customScenario}`;
      } else {
        const scenarios = {
          morning_routine: `Morning Routine Scenario: You are discussing daily morning routines. Ask about wake-up time, breakfast habits, morning preparations, and how the learner starts their day.`,
          school_conversation: `School Conversation Scenario: You are a fellow student or teacher at school. Discuss classes, assignments, school events, and school life in general.`,
          restaurant: `Restaurant Ordering Scenario: You are a restaurant staff and the learner is a customer. Guide the conversation about menu recommendations, ordering, special requests, and other restaurant interactions.`,
        };
        
        systemMessage.content += `\n\n${scenarios[scenarioType] || scenarios.restaurant}`;
      }
    }
    
    if (difficultyLevel) {
      const difficultySettings = {
        beginner: `Difficulty: Beginner - Use basic greetings, simple sentences, and everyday expressions. Keep grammar structures simple and use only common vocabulary.`,
        intermediate: `Difficulty: Intermediate - You can use more complex sentence structures and wider vocabulary. Explain if the learner seems to have difficulty understanding.`,
        advanced: `Difficulty: Advanced - Speak at a natural pace using idiomatic expressions, complex grammar, and varied vocabulary. Point out subtle errors in the learner's speech.`
      };
      
      systemMessage.content += `\n\n${difficultySettings[difficultyLevel] || difficultySettings.beginner}`;
    }
    
    const recentMessages = chatMessages.slice(-10);
    return [systemMessage, ...recentMessages];
  }, [chatLanguage, chatMessages, difficultyLevel, scenarioType, customScenario]);

  // GPT에 채팅 메시지 전송
  const sendChatMessage = useCallback(async () => {
    if (!apiKey) {
      alert('Please enter and save your API key first.');
      return;
    }
    
    if (!chatInput.trim()) {
      return;
    }
    
    const userMessage = chatInput.trim();
    setChatInput('');
    
    const newUserMessage = {
      role: 'user',
      content: userMessage
    };
    
    setChatMessages(prevMessages => [...prevMessages, newUserMessage]);
    setIsChatProcessing(true);
    
    try {
      const chatContext = buildChatContext();
      
      const response = await fetch(API_ENDPOINTS.OPENAI_CHAT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`,
        },
        body: JSON.stringify({
          model: 'gpt-4-turbo',
          messages: [
            ...chatContext,
            newUserMessage
          ],
          temperature: 0.7,
        }),
      });

      if (!response.ok) {
        throw new Error(`HTTP error! Status: ${response.status}`);
      }

      const data = await response.json();
      const assistantResponse = data.choices?.[0]?.message?.content || 'Sorry, I couldn\'t generate a response.';
      
      const newAssistantMessage = {
        role: 'assistant',
        content: assistantResponse
      };
      
      setChatMessages(prevMessages => [...prevMessages, newAssistantMessage]);
      
      setTimeout(() => {
        try {
          stopSpeech();
          speakWithEnhancedVoice(assistantResponse, chatPlaybackRate, true);
        } catch (voiceError) {
          console.error('음성 출력 오류:', voiceError);
        }
      }, 200);
      
    } catch (error) {
      console.error('Chat API request error:', error);
      
      setChatMessages(prevMessages => [
        ...prevMessages, 
        { 
          role: 'system', 
          content: '🤖 GPT-4 Turbo로 응답 생성 중...'
        }
      ]);
    } finally {
      setIsChatProcessing(false);
    }
  }, [apiKey, buildChatContext, chatInput, setChatInput, setChatMessages, setIsChatProcessing, chatPlaybackRate, speakWithEnhancedVoice, stopSpeech]);

  // 대화 피드백 생성
  const generateConversationFeedback = useCallback(async () => {
    if (!apiKey) {
      alert('OpenAI API 키를 먼저 입력해주세요.');
      return;
    }
    
    if (chatMessages.length < 3) {
      alert('충분한 대화가 없습니다. 더 대화를 나눈 후 피드백을 요청해주세요.');
      return;
    }
    
    setConversationEnded(true);
    
    const userMessages = chatMessages.filter(msg => msg.role === 'user');
    
    if (userMessages.length === 0) {
      alert('사용자 메시지가 없습니다.');
      return;
    }
    
    try {
      setIsChatProcessing(true);
      
      const allUserMessages = userMessages.map(msg => msg.content).join('\n\n');
      const feedbackLangName = feedbackLanguage || 'English';
      
      const response = await fetch(API_ENDPOINTS.OPENAI_CHAT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`,
        },
        body: JSON.stringify({
          model: 'gpt-4-turbo', 
          messages: [
            {
              role: 'system',
              content: `당신은 ${chatLanguage || 'English'} 언어 교육 전문가입니다. 
              다음 대화에서 사용자의 메시지를 분석하고 상세한 피드백을 제공해주세요.
              
              다음 카테고리에 따라 점수(1-5)와 구체적인 피드백을 제공해주세요:
              1. 발음 및 억양 문제 (특히 잘못 발음된 단어들)
              2. 문법 오류 및 수정 방법
              3. 어휘 사용 (적절성 및 다양성)
              4. 유창성 평가
              5. 전반적인 인상
              
              각 오류에 대해 구체적인 예시와 올바른 표현을 제시해주세요.
              마지막에는 향상을 위한 조언을 추가해주세요.
              
              피드백은 ${feedbackLangName}로 작성해주세요.`
            },
            {
              role: 'user',
              content: `시나리오: ${scenarioType}\n난이도: ${difficultyLevel}\n\n사용자 메시지:\n${allUserMessages}`
            }
          ],
          temperature: 0.7,
        }),
      });

      if (!response.ok) {
        throw new Error(`HTTP error! Status: ${response.status}`);
      }

      const data = await response.json();
      const feedbackContent = data.choices?.[0]?.message?.content || '피드백을 생성할 수 없습니다.';
      
      setChatMessages(prev => [...prev, {
        id: Date.now(),
        role: 'feedback',
        content: feedbackContent
      }]);
      
    } catch (error) {
      console.error('Feedback Request Error:', error);
      alert('An error occurred while generating feedback: ' + error.message);
    } finally {
      setIsChatProcessing(false);
    }
  }, [apiKey, chatMessages, chatLanguage, scenarioType, difficultyLevel, feedbackLanguage, setConversationEnded, setIsChatProcessing, setChatMessages]);

  // 대화 내용 다운로드
  const downloadConversation = useCallback(() => {
    if (chatMessages.length === 0) {
      alert('No conversation available for download.');
      return;
    }
    
    let htmlContent = `
    <!DOCTYPE html>
    <html>
    <head>
      <title>${chatLanguage || 'English'} 대화 연습 기록</title>
      <meta charset="UTF-8">
      <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; max-width: 800px; margin: 0 auto; padding: 20px; }
        h1 { color: #3498db; text-align: center; }
        .conversation-info { background-color: #f8f9fa; padding: 15px; border-radius: 8px; margin-bottom: 20px; }
        .message { padding: 10px 15px; margin-bottom: 10px; border-radius: 8px; }
        .user { background-color: #ebf5fb; border-left: 4px solid #3498db; }
        .assistant { background-color: #eafaf1; border-left: 4px solid #2ecc71; }
        .feedback { background-color: #fff3e0; border-left: 4px solid #f39c12; padding: 15px; margin-top: 20px; }
        .feedback h3 { color: #f39c12; }
        .date { color: #7f8c8d; font-size: 0.8em; text-align: right; }
      </style>
    </head>
    <body>
      <h1>${chatLanguage || 'English'} 대화 연습 기록</h1>
      
      <div class="conversation-info">
        <p><strong>시나리오:</strong> ${scenarioType}</p>
        <p><strong>난이도:</strong> ${difficultyLevel}</p>
        <p><strong>날짜:</strong> ${new Date().toLocaleString()}</p>
      </div>
      
      <div class="conversation">
    `;

    chatMessages.forEach(message => {
      if (message.role === 'feedback') {
        htmlContent += `
        <div class="feedback">
          <h3>🎓 종합 피드백</h3>
          <div>${message.content.replace(/\n/g, '<br>')}</div>
        </div>`;
      } else {
        htmlContent += `
        <div class="message ${message.role}">
          <strong>${message.role === 'user' ? '나' : '튜터'}:</strong>
          <div>${message.content}</div>
        </div>`;
      }
    });

    htmlContent += `
      </div>
    </body>
    </html>
    `;

    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${chatLanguage || 'English'}_대화_${new Date().toLocaleDateString().replace(/\//g, '-')}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, [chatMessages, chatLanguage, scenarioType, difficultyLevel]);

  // 채팅 메시지 음성 컨트롤
  const speakChatMessage = useCallback((message) => {
    speakWithEnhancedVoice(message, chatPlaybackRate, true);
  }, [chatPlaybackRate, speakWithEnhancedVoice]);

  // 채팅 메시지 번역
  const translateChatMessage = useCallback(async (message, translationLang) => {
    if (!message) return;
    
    try {
      const targetLang = translationLang?.split('-')[0];
      const sourceLang = chatLanguage?.split('-')[0];
      
      if (!targetLang || !sourceLang) {
        return "Translation language codes unavailable.";
      }
      
      const myMemoryUrl = `${API_ENDPOINTS.MYMEMORY_TRANSLATE}?q=${encodeURIComponent(message)}&langpair=${sourceLang}|${targetLang}`;
      const myMemoryResponse = await fetch(myMemoryUrl);
     
      if (myMemoryResponse.ok) {
        const data = await myMemoryResponse.json();
        if (data.responseData) {
          return data.responseData.translatedText;
        }
      }
      
      return "Translation unavailable.";
    } catch (error) {
      console.error('Chat translation error:', error);
      return "Translation error.";
    }
  }, [chatLanguage]);

  // 채팅 초기화
  const clearChat = useCallback(() => {
    setChatMessages([]);
    stopSpeech();
    setConversationEnded(false);
    setChatInput('');
    setIsChatProcessing(false);
    console.log('채팅이 초기화되었습니다. 피드백 기능이 재활성화되었습니다.');
  }, [setChatMessages, stopSpeech, setConversationEnded, setChatInput, setIsChatProcessing]);

  return {
    sendChatMessage,
    generateConversationFeedback,
    downloadConversation,
    speakChatMessage,
    translateChatMessage,
    clearChat
  };
};