// App.js - 축소된 버전 (5개 모드 제거)
import React, { useRef, useEffect, useCallback, useMemo } from 'react';
import './App.css';
import TutorModeManager from './TutorModeManager';
import FixedModelAnswerMode from './FixedModelAnswerMode';
import { useSpeechRecognition } from './AudioRecognition';

// ===== 분리된 모듈들 Import =====
import { 
  languages, 
  scenarioOptions, 
  DEFAULT_SETTINGS,
  STORAGE_KEYS
} from './appData';

import { 
  useAppState, 
  useAudioControls, 
  useChatFunctions
} from './appHooks';

import { 
  renderHeader,
  renderLanguageSelector, 
  renderTabMenu,
  renderChatTutorMode,
  renderFixedModelMode
} from './appRenderFunctions';

const App = () => {
  // ===== 상태 관리 (커스텀 훅 사용) =====
  const appState = useAppState();
  
  // 상태 비구조화 할당으로 가독성 향상
  const {
    // 기본 설정
    selectedLanguage, setSelectedLanguage,
    apiKey, setApiKey,
    availableVoices, setAvailableVoices,
    selectedVoiceType, setSelectedVoiceType,
    selectedVoiceGender, setSelectedVoiceGender,
    questionPlaybackRate, setQuestionPlaybackRate,
    feedbackLanguage, setFeedbackLanguage,
    
    // 모드 상태
    showTutorMode, setShowTutorMode,
    showFixedModelMode, setShowFixedModelMode,
    chatMode, setChatMode,
    
    // 질문 & 답변 상태
    audioUrl, setAudioUrl,
    audioBlob, setAudioBlob,
    isRecording, setIsRecording,
    transcript, setTranscript,
    
    // 채팅 관련
    conversationEnded, setConversationEnded,
    chatMessages, setChatMessages,
    chatInput, setChatInput,
    isChatProcessing, setIsChatProcessing,
    chatLanguage, setChatLanguage,
    scenarioType, setScenarioType,
    difficultyLevel, setDifficultyLevel,
    chatPlaybackRate, setChatPlaybackRate,
    chatTranslationLanguage, setChatTranslationLanguage,
    isAiSpeaking, setIsAiSpeaking,
    customScenario, setCustomScenario,
    showCustomScenarioModal, setShowCustomScenarioModal
  } = appState;

  // ===== Refs =====
  const { recognitionRef, mediaRecorderRef, audioChunksRef } = useSpeechRecognition();
  const chatEndRef = useRef(null);

  // ===== 오디오 제어 훅 =====
  const audioControls = useAudioControls({
    availableVoices,
    selectedLanguage,
    selectedVoiceGender,
    selectedVoiceType,
    questionPlaybackRate,
    chatLanguage,
    chatPlaybackRate,
    recognitionRef,
    mediaRecorderRef,
    audioChunksRef,
    setIsRecording,
    setTranscript,
    setAudioBlob,
    setAudioUrl,
    setIsAiSpeaking,
    isRecording
  });

  const { speakWithEnhancedVoice, stopSpeech, startRecording, stopRecording } = audioControls;

  // ===== 채팅 기능 훅 =====
  const chatFunctions = useChatFunctions({
    apiKey,
    chatLanguage,
    chatMessages,
    setChatMessages,
    chatInput,
    setChatInput,
    isChatProcessing,
    setIsChatProcessing,
    difficultyLevel,
    scenarioType,
    customScenario,
    setConversationEnded,
    feedbackLanguage,
    chatPlaybackRate,
    speakWithEnhancedVoice,
    stopSpeech
  });

  const { 
    sendChatMessage, 
    generateConversationFeedback, 
    downloadConversation, 
    speakChatMessage, 
    translateChatMessage, 
    clearChat 
  } = chatFunctions;

  // ===== 상수 =====
  const translationLanguages = useMemo(() => 
    languages.filter(lang => lang.code !== selectedLanguage),
  [selectedLanguage]);

  // API 키 저장
  const handleApiKeySubmit = useCallback(() => {
    localStorage.setItem(STORAGE_KEYS.API_KEY, apiKey);
    alert('API key saved successfully!');
  }, [apiKey]);

  // ===== 음성 초기화 =====
  useEffect(() => {
    const initVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      setAvailableVoices(voices);
      console.log("Available voices:", voices.map(v => `${v.name} (${v.lang})`));
    };

    if (window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = initVoices;
      setTimeout(() => {
        if (window.speechSynthesis.getVoices().length > 0) {
          initVoices();
        }
      }, 200);
    }
    
    return () => {
      if (window.speechSynthesis) {
        window.speechSynthesis.onvoiceschanged = null;
      }
    };
  }, [setAvailableVoices]);

  useEffect(() => {
    if (chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages]);

  // ===== 페이지 로드 확인 =====
  useEffect(() => {
    const timer = setTimeout(() => {
      const mainContent = document.querySelector('.language-selector, .header-controls');
      if (!mainContent) {
        const fallbackMsg = document.getElementById('fallbackMessage');
        if (fallbackMsg) {
          fallbackMsg.style.display = 'block';
        }
      }
    }, 2000);
    
    return () => clearTimeout(timer);
  }, []);

  // ===== 메인 렌더링 =====
  return (
    <div className="app-container">
      {/* 헤더 */}
      {renderHeader()}
      
      {/* 언어 선택기 */}
      {renderLanguageSelector({
        apiKey,
        setApiKey,
        handleApiKeySubmit,
        languages,
        selectedLanguage,
        setSelectedLanguage,
        chatMode,
        setChatLanguage
      })}

      {/* 탭 메뉴 (축소된 버전) */}
      {renderTabMenu({
        showFixedModelMode,
        showTutorMode,
        setShowFixedModelMode,
        setShowTutorMode
      })}

      {/* 메인 콘텐츠 영역 */}
      {showTutorMode ? (
        <div className="modal-container" style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          zIndex: 9999,
          backgroundColor: 'rgba(0, 0, 0, 0.8)',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          overflow: 'hidden'
        }}>
          <TutorModeManager
            apiKey={apiKey}
            selectedLanguage={selectedLanguage}
            level={difficultyLevel}
            onClose={() => setShowTutorMode(false)}
          />
        </div>
      ) : showFixedModelMode ? (
        <FixedModelAnswerMode 
          selectedLanguage={selectedLanguage}
          onClose={() => setShowFixedModelMode(false)}
        />
      ) : (
        renderChatTutorMode({
          chatLanguage,
          scenarioType,
          setScenarioType,
          difficultyLevel,
          setDifficultyLevel,
          customScenario,
          setCustomScenario,
          showCustomScenarioModal,
          setShowCustomScenarioModal,
          clearChat,
          chatPlaybackRate,
          setChatPlaybackRate,
          chatTranslationLanguage,
          setChatTranslationLanguage,
          feedbackLanguage,
          setFeedbackLanguage,
          languages,
          translationLanguages,
          chatMessages,
          isChatProcessing,
          speakChatMessage,
          translateChatMessage,
          conversationEnded,
          generateConversationFeedback,
          downloadConversation,
          chatInput,
          setChatInput,
          sendChatMessage,
          startRecording,
          stopRecording,
          isRecording,
          transcript,
          chatEndRef,
          scenarioOptions,
          isAiSpeaking,
          languageData: {
            [chatLanguage]: {
              flag: languages.find(l => l.code === chatLanguage)?.flag || "🌐",
              name: languages.find(l => l.code === chatLanguage)?.name || "English"
            }
          }
        })
      )}

      {/* 페이지 로드 실패 대체 메시지 */}
      <div style={{marginTop: '30px', textAlign: 'center', display: 'none'}} id="fallbackMessage">
        <p style={{color: 'white', fontSize: '18px', margin: '20px 0'}}>
          일부 기능이 제대로 로드되지 않았습니다. 새로고침 해보세요.
        </p>
        <button 
          style={{
            background: '#3498db', 
            color: 'white', 
            padding: '10px 20px', 
            border: 'none', 
            borderRadius: '8px', 
            cursor: 'pointer'
          }}
          onClick={() => window.location.reload()}
        >
          새로고침
        </button>
      </div>
    </div>
  );
};

export default App;