// ===== Fixed Model 설정 =====
export const fixedModelConfig = {
  SUPPORTED_LANGUAGES: ["English", "Korean", "Japanese", "Chinese"],
  SUPPORTED_COURSES: ["Basic", "Expressor", "Elite"],
  SUPPORTED_LEVELS: ["Beginner", "Intermediate", "Advanced"],
  DEFAULT_LANGUAGE: "English",
  DEFAULT_COURSE: "Elite",
  DEFAULT_LEVEL: "Intermediate",
  MAX_QUESTIONS_PER_SESSION: 50,
  AUTO_PLAY_QUESTION: true,
  SHOW_PROGRESS_BAR: true,
  CACHE_DURATION: 5 * 60 * 1000, // 5분
  SHUFFLE_QUESTIONS: true,
  ENABLE_MODEL_ANSWER_TOGGLE: true
};

// ===== 유틸리티 함수들 =====

// 언어별 테스트 타입 가져오기
export const getTestTypeByLanguage = (language) => {
  const mapping = {
    'English': 'englishElite', // 기본적으로 Elite 코스
    'Korean': 'korean',
    'Japanese': 'japanese', 
    'Chinese': 'chinese'
  };
  return mapping[language];
};

// 언어와 코스에 따른 테스트 타입 가져오기
export const getTestTypeByCourse = (language, course) => {
  if (language === 'English') {
    return course === 'Expressor' ? 'englishExpress' : 'englishElite';
  }
  return getTestTypeByLanguage(language);
};

// 사용 가능한 코스 가져오기
export const getAvailableCourses = (language) => {
  if (!language || !languageData[language]) {
    return [];
  }
  return languageData[language].courses;
};

// 사용 가능한 파트 가져오기  
export const getAvailableParts = (language, course = null) => {
  const testType = course ? 
    getTestTypeByCourse(language, course) : 
    getTestTypeByLanguage(language);
    
  if (!testType || !mockTestData[testType]) {
    return [];
  }
  
  return mockTestData[testType].parts.map((part, index) => ({
    id: index + 1,
    name: part.name,
    description: part.description,
    questions: part.questions
  }));
};

// 총 질문 수 계산
export const getTotalQuestions = (language, course = null) => {
  const parts = getAvailableParts(language, course);
  return parts.reduce((total, part) => total + part.questions, 0);
};

// 테스트 유효성 검사
export const validateTestSelection = (language, course, level, part) => {
  const errors = [];
  
  if (!fixedModelConfig.SUPPORTED_LANGUAGES.includes(language)) {
    errors.push(`Unsupported language: ${language}`);
  }
  
  if (!fixedModelConfig.SUPPORTED_COURSES.includes(course)) {
    errors.push(`Unsupported course: ${course}`);
  }
  
  if (!fixedModelConfig.SUPPORTED_LEVELS.includes(level)) {
    errors.push(`Unsupported level: ${level}`);
  }
  
  const availableParts = getAvailableParts(language, course);
  const partExists = availableParts.some(p => p.name === part);
  
  if (!partExists) {
    errors.push(`Part "${part}" not available for ${language} ${course}`);
  }
  
  return {
    isValid: errors.length === 0,
    errors
  };
};

// 언어 설정 가져오기
export const getLanguageConfig = () => {
  return Object.keys(languageData).reduce((config, lang) => {
    config[lang] = {
      flag: languageData[lang].flag,
      name: languageData[lang].name,
      courses: languageData[lang].courses
    };
    return config;
  }, {});
};

// Mock 질문 생성 (폴백용)
export const generateMockQuestions = (language, course, part, level = 'Intermediate') => {
  const baseQuestions = {
    'Self Introduction': [
      'Tell me about yourself and your background.',
      'What are your main interests and hobbies?',
      'Describe your personality and characteristics.'
    ],
    'Daily Life': [
      'Describe your typical daily routine.',
      'What do you usually do on weekends?',
      'How do you spend your free time?'
    ],
    'Work & Career': [
      'Tell me about your current job or studies.',
      'What are your career goals?',
      'Describe a challenging work situation you faced.'
    ],
    '자기소개': [
      '자신에 대해 소개해 주세요.',
      '당신의 취미와 관심사는 무엇인가요?',
      '당신의 성격에 대해 말해주세요.'
    ],
    '일상생활': [
      '평소 하루 일과를 설명해 주세요.',
      '주말에는 주로 무엇을 하나요?',
      '여가시간을 어떻게 보내나요?'
    ]
  };

  const questions = baseQuestions[part] || [
    `Tell me about your experience with ${part}.`,
    `How would you describe your approach to ${part}?`,
    `What challenges have you faced regarding ${part}?`
  ];

  return questions.map((question, index) => ({
    language,
    course,
    level,
    part,
    question,
    model_answer: `This is a sample model answer for "${question}". A good response should be detailed, personal, and well-structured. You should provide specific examples and explain your thoughts clearly.`,
    show_model_answer: index < 2 ? 'yes' : 'no', // 처음 2개만 모범답안 표시
    category: part,
    id: `mock_${Date.now()}_${index}`
  }));
};

// 기본 내보내기
export default {
  mockTestData,
  languageData,
  fixedModelConfig,
  getTestTypeByLanguage,
  getTestTypeByCourse,
  getAvailableCourses,
  getAvailableParts,
  getTotalQuestions,
  validateTestSelection,
  getLanguageConfig,
  generateMockQuestions
};