// AudioRecognition.js - 음성 인식 재사용 문제 해결 버전
import { useRef, useEffect, useState, useCallback } from 'react';

// 디버깅 모드 설정
const DEBUG = true;

// 디버깅 로그 함수
const logInfo = (message, data) => {
  if (DEBUG) {
    const timestamp = new Date().toLocaleTimeString();
    if (data) {
      console.log(`[AudioRecognition ${timestamp}] ${message}`, data);
    } else {
      console.log(`[AudioRecognition ${timestamp}] ${message}`);
    }
  }
};

/**
 * 개선된 음성 인식 React Hook - 재사용 문제 해결
 * @param {string} language - 음성 인식 언어
 * @returns {Object} 음성 인식 관련 객체 참조와 상태
 */
export const useSpeechRecognition = (language) => {
  const recognitionRef = useRef(null);
  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const streamRef = useRef(null);
  const isActiveRef = useRef(false);
  
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [audioUrl, setAudioUrl] = useState('');
  const [recordingError, setRecordingError] = useState(null);
  
  // 안드로이드 디바이스 감지
  const isAndroid = /Android/i.test(navigator.userAgent);

  // 완전한 정리 함수
  const completeCleanup = useCallback(() => {
    logInfo('완전한 정리 시작');
    
    // 음성 인식 정리
    if (recognitionRef.current) {
      try {
        recognitionRef.current.stop();
        recognitionRef.current.abort();
      } catch (e) {
        logInfo('인식기 정리 중 오류 (무시 가능):', e);
      }
      
      // 이벤트 핸들러 제거
      recognitionRef.current.onresult = null;
      recognitionRef.current.onend = null;
      recognitionRef.current.onerror = null;
      recognitionRef.current.onstart = null;
      recognitionRef.current = null;
    }
    
    // 미디어 레코더 정리
    if (mediaRecorderRef.current) {
      try {
        if (mediaRecorderRef.current.state === 'recording') {
          mediaRecorderRef.current.stop();
        }
      } catch (e) {
        logInfo('레코더 정리 중 오류 (무시 가능):', e);
      }
      mediaRecorderRef.current = null;
    }
    
    // 미디어 스트림 정리
    if (streamRef.current) {
      try {
        streamRef.current.getTracks().forEach(track => {
          track.stop();
          logInfo('트랙 정리됨:', track.kind);
        });
      } catch (e) {
        logInfo('스트림 정리 중 오류 (무시 가능):', e);
      }
      streamRef.current = null;
    }
    
    // 오디오 URL 정리
    if (audioUrl) {
      try {
        URL.revokeObjectURL(audioUrl);
      } catch (e) {
        logInfo('URL 정리 중 오류 (무시 가능):', e);
      }
    }
    
    // 상태 초기화
    isActiveRef.current = false;
    audioChunksRef.current = [];
    
    logInfo('완전한 정리 완료');
  }, [audioUrl]);

  // 새로운 음성 인식 객체 생성
  const createFreshRecognition = useCallback(() => {
    logInfo('새로운 음성 인식 객체 생성 시작');
    
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      throw new Error('이 브라우저는 음성 인식을 지원하지 않습니다.');
    }

    const recognition = new SpeechRecognition();
    
    // 안드로이드 최적화 설정
    if (isAndroid) {
      recognition.continuous = false;
      recognition.interimResults = true;
      recognition.maxAlternatives = 1;
    } else {
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.maxAlternatives = 1;
    }
    
    recognition.lang = language || 'ko-KR';
    
    let finalTranscript = '';
    
    // 결과 이벤트 핸들러
    recognition.onresult = (event) => {
      if (!isActiveRef.current) return;
      
      let interimTranscript = '';
      
      for (let i = event.resultIndex; i < event.results.length; i++) {
        const transcript = event.results[i][0].transcript;
        if (event.results[i].isFinal) {
          finalTranscript += transcript + ' ';
          logInfo('최종 인식 결과:', transcript);
        } else {
          interimTranscript += transcript;
        }
      }
      
      const combinedTranscript = (finalTranscript + interimTranscript).trim();
      
      if (combinedTranscript.length > 0) {
        setTranscript(combinedTranscript);
      }
    };
    
    // 시작 이벤트 핸들러
    recognition.onstart = () => {
      if (!isActiveRef.current) return;
      logInfo('음성 인식 시작됨');
      setIsListening(true);
      setRecordingError(null);
    };
    
    // 종료 이벤트 핸들러
    recognition.onend = () => {
      logInfo('음성 인식 종료됨', { isActive: isActiveRef.current });
      
      if (isActiveRef.current && isAndroid) {
        // 안드로이드에서 자동 재시작
        try {
          setTimeout(() => {
            if (isActiveRef.current && recognitionRef.current) {
              logInfo('안드로이드 인식기 재시작');
              recognitionRef.current.start();
            }
          }, 100);
        } catch (error) {
          logInfo('안드로이드 재시작 실패:', error);
        }
      }
    };
    
    // 오류 이벤트 핸들러
    recognition.onerror = (event) => {
      logInfo('음성 인식 오류:', event.error);
      
      if (event.error === 'no-speech') {
        logInfo('음성이 감지되지 않았습니다');
      } else if (event.error === 'audio-capture') {
        setRecordingError('마이크를 사용할 수 없습니다. 마이크 권한을 확인해주세요.');
      } else if (event.error === 'not-allowed') {
        setRecordingError('마이크 사용 권한이 거부되었습니다.');
      } else if (event.error === 'network') {
        setRecordingError('네트워크 오류가 발생했습니다.');
      } else if (event.error !== 'aborted') {
        setRecordingError(`음성 인식 오류: ${event.error}`);
      }
    };
    
    logInfo('새로운 음성 인식 객체 생성 완료');
    return recognition;
  }, [language, isAndroid]);

  // 새로운 미디어 스트림 가져오기
  const getFreshMediaStream = useCallback(async () => {
    logInfo('새로운 미디어 스트림 요청');
    
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: {
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
          sampleRate: 16000
        } 
      });
      
      logInfo('새로운 미디어 스트림 획득 성공');
      return stream;
    } catch (error) {
      logInfo('미디어 스트림 획득 실패:', error);
      throw error;
    }
  }, []);

  // 새로운 미디어 레코더 생성
  const createFreshMediaRecorder = useCallback((stream) => {
    logInfo('새로운 미디어 레코더 생성');
    
    // MIME 타입 결정
    let mimeType = 'audio/webm;codecs=opus';
    if (isAndroid) {
      if (MediaRecorder.isTypeSupported('audio/webm')) {
        mimeType = 'audio/webm';
      } else if (MediaRecorder.isTypeSupported('audio/mp4')) {
        mimeType = 'audio/mp4';
      } else {
        mimeType = '';
      }
    }
    
    const recorderOptions = mimeType ? { mimeType } : {};
    const recorder = new MediaRecorder(stream, recorderOptions);
    
    // 데이터 이벤트 핸들러
    recorder.ondataavailable = (event) => {
      if (event.data.size > 0 && isActiveRef.current) {
        audioChunksRef.current.push(event.data);
        logInfo(`오디오 청크 수신: ${event.data.size} 바이트`);
      }
    };
    
    // 중지 이벤트 핸들러
    recorder.onstop = () => {
      logInfo('미디어 레코더 중지됨', { 
        chunksCount: audioChunksRef.current.length 
      });
      
      if (audioChunksRef.current.length > 0) {
        try {
          const audioBlob = new Blob(audioChunksRef.current, { 
            type: mimeType || 'audio/webm' 
          });
          const url = URL.createObjectURL(audioBlob);
          setAudioUrl(url);
          logInfo('오디오 URL 생성 성공');
        } catch (error) {
          logInfo('오디오 블롭 생성 오류:', error);
          setRecordingError('오디오 처리 중 오류가 발생했습니다.');
        }
      } else {
        logInfo('오디오 청크가 없음');
      }
    };
    
    recorder.onerror = (event) => {
      logInfo('미디어 레코더 오류:', event.error);
    };
    
    return recorder;
  }, [isAndroid]);

  // 음성 인식 시작 (완전히 새로 작성)
  const startListening = useCallback(async () => {
    logInfo('=== 음성 인식 시작 요청 ===');
    
    try {
      // 1. 완전한 정리
      completeCleanup();
      
      // 2. 상태 초기화
      setRecordingError(null);
      setAudioUrl('');
      setTranscript('');
      audioChunksRef.current = [];
      isActiveRef.current = true;
      
      // 3. 새로운 미디어 스트림 획득
      const stream = await getFreshMediaStream();
      streamRef.current = stream;
      
      // 4. 새로운 미디어 레코더 생성 및 시작
      const recorder = createFreshMediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      recorder.start(100); // 100ms 간격으로 데이터 수집
      
      // 5. 새로운 음성 인식 객체 생성 및 시작
      const recognition = createFreshRecognition();
      recognitionRef.current = recognition;
      
      // 짧은 지연 후 음성 인식 시작
      setTimeout(() => {
        if (isActiveRef.current && recognitionRef.current) {
          try {
            recognitionRef.current.start();
            logInfo('음성 인식 시작 성공');
          } catch (error) {
            logInfo('음성 인식 시작 오류:', error);
            throw error;
          }
        }
      }, 100);
      
    } catch (error) {
      logInfo('녹음 시작 실패:', error);
      isActiveRef.current = false;
      setRecordingError(
        error.name === 'NotAllowedError' 
          ? '마이크 접근 권한이 거부되었습니다.' 
          : '녹음을 시작할 수 없습니다.'
      );
      setIsListening(false);
      completeCleanup();
    }
  }, [completeCleanup, getFreshMediaStream, createFreshMediaRecorder, createFreshRecognition]);
  
  // 음성 인식 중지
  const stopListening = useCallback(async () => {
    logInfo('=== 음성 인식 중지 요청 ===');
    
    isActiveRef.current = false;
    setIsListening(false);
    
    // 음성 인식 중지
    if (recognitionRef.current) {
      try {
        recognitionRef.current.stop();
        logInfo('음성 인식 중지됨');
      } catch (error) {
        logInfo('음성 인식 중지 오류:', error);
      }
    }
    
    // 미디어 레코더 중지
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      try {
        mediaRecorderRef.current.stop();
        logInfo('미디어 레코더 중지됨');
      } catch (error) {
        logInfo('미디어 레코더 중지 오류:', error);
      }
    }
    
    // 스트림 정리는 나중에 completeCleanup에서 처리
    return Promise.resolve();
  }, []);
  
  // 오디오 데이터 초기화
  const resetAudio = useCallback(() => {
    logInfo('오디오 데이터 초기화');
    setTranscript('');
    setAudioUrl('');
    setRecordingError(null);
    audioChunksRef.current = [];
  }, []);
  
  // 컴포넌트 언마운트 시 정리
  useEffect(() => {
    return () => {
      logInfo('컴포넌트 언마운트 - 전체 정리');
      isActiveRef.current = false;
      completeCleanup();
    };
  }, [completeCleanup]);
  
  return {
    recognitionRef,
    mediaRecorderRef,
    audioChunksRef,
    isListening,
    transcript,
    audioUrl,
    recordingError,
    startListening,
    stopListening,
    resetAudio,
    setTranscript,
    isAndroid
  };
};

// 기존 함수들은 그대로 유지
export const createSpeechRecognition = (language, onTranscriptChange, onRecordingStateChange) => {
  const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SpeechRecognition) {
    console.error('이 브라우저는 음성 인식을 지원하지 않습니다.');
    return null;
  }

  const recognition = new SpeechRecognition();
  
  const isAndroid = /Android/i.test(navigator.userAgent);
  logInfo("안드로이드 디바이스:", isAndroid);
  
  if (isAndroid) {
    recognition.continuous = false;
    recognition.interimResults = true;
    recognition.maxAlternatives = 3;
    logInfo("안드로이드 최적화 설정 적용됨");
  } else {
    recognition.continuous = true;
    recognition.interimResults = true;
  }
  
  recognition.lang = language || 'en-US';
  logInfo("인식 언어 설정:", recognition.lang);
  
  let finalTranscript = '';
  let restartCount = 0;
  const MAX_RESTART_ATTEMPTS = 5;
  
  recognition.onresult = (event) => {
    let interimTranscript = '';
    
    for (let i = event.resultIndex; i < event.results.length; i++) {
      const transcript = event.results[i][0].transcript;
      if (event.results[i].isFinal) {
        finalTranscript += transcript + ' ';
        logInfo("최종 인식 결과:", transcript);
      } else {
        interimTranscript += transcript;
      }
    }
    
    const combinedTranscript = finalTranscript + interimTranscript;
    
    if (onTranscriptChange && combinedTranscript.trim().length > 0) {
      onTranscriptChange(combinedTranscript);
    }
  };
  
  recognition.onstart = () => {
    logInfo("음성 인식 시작됨");
    restartCount = 0;
    if (onRecordingStateChange) {
      onRecordingStateChange(true);
    }
  };
  
  recognition.onend = () => {
    logInfo("음성 인식 종료됨");
    
    if (isAndroid) {
      try {
        if (onRecordingStateChange && restartCount < MAX_RESTART_ATTEMPTS) {
          logInfo("안드로이드 인식 재시작 시도:", restartCount + 1);
          restartCount++;
          
          setTimeout(() => {
            try {
              recognition.start();
              logInfo("인식기 재시작 성공");
            } catch (error) {
              logInfo("인식기 재시작 실패:", error);
              if (onRecordingStateChange) {
                onRecordingStateChange(false);
              }
            }
          }, 300);
        } else {
          logInfo("최대 재시작 횟수 초과 또는 재시작 중단");
          if (onRecordingStateChange) {
            onRecordingStateChange(false);
          }
        }
      } catch (error) {
        console.error('Recognition onend handler error:', error);
        if (onRecordingStateChange) {
          onRecordingStateChange(false);
        }
      }
    } else {
      if (onRecordingStateChange) {
        onRecordingStateChange(false);
      }
    }
  };
  
  recognition.onerror = (event) => {
    console.error("음성 인식 오류:", event.error);
    
    if (event.error === 'no-speech') {
      logInfo("음성이 감지되지 않았습니다. 마이크에 더 가까이 말씀해보세요.");
    } else if (event.error === 'audio-capture') {
      logInfo("마이크를 사용할 수 없습니다. 마이크 권한을 확인해보세요.");
    } else if (event.error === 'not-allowed') {
      logInfo("마이크 사용 권한이 거부되었습니다. 브라우저 설정에서 권한을 허용해주세요.");
    } else if (event.error === 'network') {
      logInfo("네트워크 오류가 발생했습니다. 인터넷 연결을 확인하세요.");
    } else if (event.error === 'aborted') {
      logInfo("음성 인식이 중단되었습니다.");
    } else {
      logInfo("알 수 없는 음성 인식 오류:", event.error);
    }
    
    if (onRecordingStateChange) {
      onRecordingStateChange(false);
    }
  };
  
  return recognition;
};

export const startAndroidOptimizedRecognition = (recognition, onListeningChange) => {
  if (!recognition) {
    logInfo("인식기가 null입니다. 재생성 필요");
    return false;
  }
  
  try {
    try {
      recognition.stop();
      logInfo("기존 인식기 중지 성공");
    } catch (e) {
      logInfo("인식기 중지 무시:", e);
    }
    
    setTimeout(() => {
      try {
        if (recognition) {
          recognition.start();
          logInfo("안드로이드 최적화 인식기 시작 성공");
          if (onListeningChange) {
            onListeningChange(true);
          }
        } else {
          logInfo("인식기가 null이어서 시작할 수 없습니다");
          if (onListeningChange) {
            onListeningChange(false);
          }
        }
      } catch (error) {
        console.error('안드로이드 최적화 인식기 시작 오류:', error);
        if (onListeningChange) {
          onListeningChange(false);
        }
      }
    }, 300);
    
    return true;
  } catch (error) {
    console.error('안드로이드 인식 시작 오류:', error);
    return false;
  }
};

export const restartAndroidRecognition = (recognition) => {
  if (!recognition) return false;
  
  try {
    recognition.stop();
    logInfo("안드로이드 인식기 재시작을 위한 중지");
  } catch (e) {
    logInfo("인식기 이미 중지됨:", e);
  }
  
  return new Promise((resolve) => {
    setTimeout(() => {
      try {
        if (recognition) {
          recognition.start();
          logInfo("안드로이드 인식기 재시작 성공");
          resolve(true);
        } else {
          logInfo("인식기가 null이어서 재시작할 수 없습니다");
          resolve(false);
        }
      } catch (error) {
        console.error('안드로이드 인식기 재시작 오류:', error);
        resolve(false);
      }
    }, 300);
  });
};

export const createMediaRecorder = async (mimeType = null, onDataAvailable) => {
  try {
    const stream = await navigator.mediaDevices.getUserMedia({ 
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      } 
    });
    
    const isAndroid = /Android/i.test(navigator.userAgent);
    
    let selectedMimeType = mimeType;
    
    if (!selectedMimeType) {
      if (isAndroid) {
        if (MediaRecorder.isTypeSupported('audio/webm')) {
          selectedMimeType = 'audio/webm';
        } else if (MediaRecorder.isTypeSupported('audio/mp4')) {
          selectedMimeType = 'audio/mp4';
        } else {
          selectedMimeType = '';
        }
      } else {
        selectedMimeType = 'audio/webm;codecs=opus';
      }
    }
    
    logInfo("선택된 MIME 타입:", selectedMimeType || "기본값");
    
    const recorderOptions = selectedMimeType ? { mimeType: selectedMimeType } : {};
    const recorder = new MediaRecorder(stream, recorderOptions);
    
    if (onDataAvailable) {
      recorder.ondataavailable = onDataAvailable;
    }
    
    recorder.onstart = () => {
      logInfo("MediaRecorder 녹음 시작됨");
    };
    
    recorder.onstop = () => {
      logInfo("MediaRecorder 녹음 중지됨");
    };
    
    recorder.onerror = (event) => {
      console.error("MediaRecorder 오류:", event.error || event);
    };
    
    return recorder;
  } catch (error) {
    console.error('미디어 레코더 생성 오류:', error);
    throw error;
  }
};

export const checkDeviceCompatibility = () => {
  const isAndroid = /Android/i.test(navigator.userAgent);
  const isSafari = /^((?!chrome|android).)*safari/i.test(navigator.userAgent);
  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) && !window.MSStream;
  
  const hasSpeechRecognition = 'SpeechRecognition' in window || 'webkitSpeechRecognition' in window;
  const hasMediaRecorder = 'MediaRecorder' in window;
  
  let supportedMimeTypes = [];
  if (hasMediaRecorder) {
    const possibleTypes = [
      'audio/webm', 
      'audio/webm;codecs=opus', 
      'audio/mp4', 
      'audio/ogg', 
      'audio/wav'
    ];
    
    supportedMimeTypes = possibleTypes.filter(type => {
      try {
        return MediaRecorder.isTypeSupported(type);
      } catch (e) {
        return false;
      }
    });
  }
  
  return {
    isAndroid,
    isSafari,
    isIOS,
    hasSpeechRecognition,
    hasMediaRecorder,
    supportedMimeTypes,
    browserName: getBrowserName(),
    isCompatible: hasSpeechRecognition && hasMediaRecorder
  };
};

function getBrowserName() {
  const userAgent = navigator.userAgent;
  let browserName;
  
  if (userAgent.match(/chrome|chromium|crios/i)) {
    browserName = "Chrome";
  } else if (userAgent.match(/firefox|fxios/i)) {
    browserName = "Firefox";
  } else if (userAgent.match(/safari/i)) {
    browserName = "Safari";
  } else if (userAgent.match(/opr\//i)) {
    browserName = "Opera";
  } else if (userAgent.match(/edg/i)) {
    browserName = "Edge";
  } else {
    browserName = "Unknown";
  }
  
  return browserName;
}

export const playAudio = (audioUrl) => {
  return new Promise((resolve, reject) => {
    if (!audioUrl) {
      reject(new Error('오디오 URL이 제공되지 않았습니다.'));
      return;
    }
    
    const audio = new Audio(audioUrl);
    
    audio.onended = () => {
      resolve();
    };
    
    audio.onerror = (error) => {
      reject(new Error('오디오 재생 오류: ' + error));
    };
    
    try {
      audio.play();
    } catch (error) {
      reject(error);
    }
  });
};

export const convertToWav = async (audioBlob) => {
  if (!audioBlob) return null;
  return audioBlob;
};