// fetchGoogleSheet.js - Google Sheets 데이터를 JSON으로 fetch하는 유틸리티

// ===== 구글 시트 설정 =====
const GOOGLE_SHEET_CONFIG = {
  // 실제 프로덕션에서는 환경변수나 설정 파일에서 가져오세요
  SHEET_ID: '1your-sheet-id-here', // 실제 시트 ID로 변경 필요
  API_KEY: 'your-google-api-key',   // Google Sheets API 키
  RANGE: 'Sheet1!A:H',              // 데이터 범위
  
  // 공개 시트를 CSV로 사용하는 경우 (API 키 불필요)
  PUBLIC_CSV_URL: 'https://docs.google.com/spreadsheets/d/{SHEET_ID}/export?format=csv&gid=0'
};

// ===== 컬럼 매핑 =====
const COLUMN_MAPPING = {
  A: 'language',          // 언어 (English, Korean, Japanese, Chinese)
  B: 'course',            // 코스 (Basic, Expressor, Elite)
  C: 'level',             // 레벨 (Beginner, Intermediate, Advanced)
  D: 'part',              // 파트 (Self Introduction, Daily Life, etc.)
  E: 'question',          // 질문 텍스트
  F: 'model_answer',      // 모범답안
  G: 'category',          // 카테고리 (Travel, Work, etc.)
  H: 'show_model_answer'  // 모범답안 표시 여부 (yes/no)
};

/**
 * CSV 텍스트를 파싱하여 JSON 객체 배열로 변환
 * @param {string} csvText - CSV 텍스트
 * @returns {Array} JSON 객체 배열
 */
const parseCSVToJSON = (csvText) => {
  const lines = csvText.trim().split('\n');
  
  if (lines.length < 2) {
    throw new Error('CSV must have at least a header row and one data row');
  }

  // 헤더 행 파싱 (첫 번째 행)
  const headers = parseCSVLine(lines[0]);
  
  // 데이터 행들 파싱
  const data = [];
  
  for (let i = 1; i < lines.length; i++) {
    const values = parseCSVLine(lines[i]);
    
    // 빈 행 건너뛰기
    if (values.length === 0 || values.every(val => !val.trim())) {
      continue;
    }
    
    // 객체 생성
    const row = {};
    headers.forEach((header, index) => {
      const columnKey = Object.keys(COLUMN_MAPPING)[index];
      const mappedKey = COLUMN_MAPPING[columnKey] || header;
      row[mappedKey] = values[index] ? values[index].trim() : '';
    });
    
    // 필수 필드 검증
    if (row.language && row.question) {
      data.push(row);
    }
  }
  
  return data;
};

/**
 * CSV 한 줄을 파싱 (콤마와 따옴표 처리)
 * @param {string} line - CSV 행
 * @returns {Array} 파싱된 값들
 */
const parseCSVLine = (line) => {
  const result = [];
  let current = '';
  let inQuotes = false;
  
  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    const nextChar = line[i + 1];
    
    if (char === '"') {
      if (inQuotes && nextChar === '"') {
        // 연속된 따옴표는 이스케이프된 따옴표
        current += '"';
        i++; // 다음 따옴표 건너뛰기
      } else {
        // 따옴표 시작/끝
        inQuotes = !inQuotes;
      }
    } else if (char === ',' && !inQuotes) {
      // 콤마로 구분 (따옴표 밖에서만)
      result.push(current);
      current = '';
    } else {
      current += char;
    }
  }
  
  // 마지막 필드 추가
  result.push(current);
  
  return result;
};

/**
 * Google Sheets API를 사용하여 데이터 fetch (API 키 필요)
 * @returns {Promise<Array>} 질문 데이터 배열
 */
const fetchWithSheetsAPI = async () => {
  const { SHEET_ID, API_KEY, RANGE } = GOOGLE_SHEET_CONFIG;
  
  if (!SHEET_ID || !API_KEY) {
    throw new Error('Google Sheets ID and API key are required');
  }
  
  const url = `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${RANGE}?key=${API_KEY}`;
  
  try {
    const response = await fetch(url);
    
    if (!response.ok) {
      throw new Error(`Sheets API error: ${response.status} ${response.statusText}`);
    }
    
    const data = await response.json();
    const rows = data.values || [];
    
    if (rows.length < 2) {
      throw new Error('Sheet must have at least a header row and one data row');
    }
    
    // 데이터 변환
    const headers = rows[0];
    const jsonData = [];
    
    for (let i = 1; i < rows.length; i++) {
      const row = rows[i];
      const item = {};
      
      headers.forEach((header, index) => {
        const columnKey = Object.keys(COLUMN_MAPPING)[index];
        const mappedKey = COLUMN_MAPPING[columnKey] || header;
        item[mappedKey] = row[index] ? row[index].trim() : '';
      });
      
      // 필수 필드가 있는 행만 추가
      if (item.language && item.question) {
        jsonData.push(item);
      }
    }
    
    return jsonData;
    
  } catch (error) {
    console.error('Failed to fetch from Sheets API:', error);
    throw error;
  }
};

/**
 * 공개 시트를 CSV로 fetch (API 키 불필요)
 * @param {string} sheetId - Google Sheets ID
 * @returns {Promise<Array>} 질문 데이터 배열
 */
const fetchPublicSheetAsCSV = async (sheetId = null) => {
  const id = sheetId || GOOGLE_SHEET_CONFIG.SHEET_ID;
  
  if (!id) {
    throw new Error('Sheet ID is required');
  }
  
  const csvUrl = `https://docs.google.com/spreadsheets/d/${id}/export?format=csv&gid=0`;
  
  try {
    const response = await fetch(csvUrl);
    
    if (!response.ok) {
      throw new Error(`Failed to fetch CSV: ${response.status} ${response.statusText}`);
    }
    
    const csvText = await response.text();
    return parseCSVToJSON(csvText);
    
  } catch (error) {
    console.error('Failed to fetch public sheet as CSV:', error);
    throw error;
  }
};

/**
 * 로컬 캐시 관리
 */
const CACHE_KEY = 'openvoiceai_sheet_data';
const CACHE_DURATION = 5 * 60 * 1000; // 5분

const getCachedData = () => {
  try {
    const cached = localStorage.getItem(CACHE_KEY);
    if (!cached) return null;
    
    const { data, timestamp } = JSON.parse(cached);
    const now = Date.now();
    
    if (now - timestamp > CACHE_DURATION) {
      localStorage.removeItem(CACHE_KEY);
      return null;
    }
    
    return data;
  } catch (error) {
    console.warn('Failed to get cached data:', error);
    return null;
  }
};

const setCachedData = (data) => {
  try {
    const cacheObject = {
      data,
      timestamp: Date.now()
    };
    localStorage.setItem(CACHE_KEY, JSON.stringify(cacheObject));
  } catch (error) {
    console.warn('Failed to cache data:', error);
  }
};

/**
 * 메인 함수: Google Sheets 데이터를 JSON으로 fetch
 * @param {Object} options - 옵션 객체
 * @param {string} options.sheetId - 시트 ID (선택사항)
 * @param {boolean} options.useCache - 캐시 사용 여부 (기본: true)
 * @param {boolean} options.useAPI - API 사용 여부 (기본: false, CSV 사용)
 * @returns {Promise<Array>} 질문 데이터 배열
 */
export const fetchGoogleSheetData = async (options = {}) => {
  const {
    sheetId = null,
    useCache = true,
    useAPI = false
  } = options;

  // 캐시된 데이터 확인
  if (useCache) {
    const cachedData = getCachedData();
    if (cachedData && cachedData.length > 0) {
      console.log('✅ Using cached sheet data');
      return cachedData;
    }
  }

  try {
    console.log('🔄 Fetching fresh data from Google Sheets...');
    
    let data;
    
    if (useAPI) {
      data = await fetchWithSheetsAPI();
    } else {
      data = await fetchPublicSheetAsCSV(sheetId);
    }
    
    // 데이터 검증
    if (!Array.isArray(data) || data.length === 0) {
      throw new Error('No valid data found in the sheet');
    }
    
    // 캐시 저장
    if (useCache) {
      setCachedData(data);
    }
    
    console.log(`✅ Successfully fetched ${data.length} questions from sheet`);
    
    return data;
    
  } catch (error) {
    console.error('❌ Failed to fetch Google Sheets data:', error);
    
    // 폴백: 캐시된 데이터라도 사용 시도
    if (useCache) {
      const cachedData = getCachedData();
      if (cachedData && cachedData.length > 0) {
        console.log('⚠️ Using stale cached data as fallback');
        return cachedData;
      }
    }
    
    // 최종 폴백: 기본 데이터 반환
    return getFallbackData();
  }
};

/**
 * 폴백 데이터 (시트를 불러올 수 없을 때 사용)
 * @returns {Array} 기본 질문 데이터
 */
