// FixedModelCard.js - 질문과 모범답안을 표시하는 카드 컴포넌트

import React, { useState, useRef } from 'react';

const FixedModelCard = ({
  question,
  questionNumber,
  totalQuestions,
  showModelAnswer,
  canShowModelAnswer,
  onToggleModelAnswer,
  selectedLanguage
}) => {
  const [isQuestionPlaying, setIsQuestionPlaying] = useState(false);
  const [isAnswerPlaying, setIsAnswerPlaying] = useState(false);
  const speechRef = useRef(null);

  // ===== 언어별 음성 설정 =====
  const getLanguageCode = () => {
    const languageMap = {
      'English': 'en-US',
      'Korean': 'ko-KR',
      'Japanese': 'ja-JP',
      'Chinese': 'zh-CN'
    };
    return languageMap[selectedLanguage] || 'en-US';
  };

  // ===== 텍스트 음성 재생 =====
  const speakText = (text, isQuestion = true) => {
    // 기존 음성 중지
    if (speechRef.current) {
      window.speechSynthesis.cancel();
      speechRef.current = null;
    }

    // 상태 설정
    if (isQuestion) {
      setIsQuestionPlaying(true);
      setIsAnswerPlaying(false);
    } else {
      setIsAnswerPlaying(true);
      setIsQuestionPlaying(false);
    }

    // 음성 합성 설정
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = getLanguageCode();
    utterance.rate = 0.9;
    utterance.pitch = 1.0;
    utterance.volume = 0.8;

    // 음성 선택 (가능한 경우)
    const voices = window.speechSynthesis.getVoices();
    const preferredVoice = voices.find(voice => voice.lang.includes(getLanguageCode()));
    if (preferredVoice) {
      utterance.voice = preferredVoice;
    }

    // 이벤트 핸들러
    utterance.onend = () => {
      setIsQuestionPlaying(false);
      setIsAnswerPlaying(false);
      speechRef.current = null;
    };

    utterance.onerror = () => {
      setIsQuestionPlaying(false);
      setIsAnswerPlaying(false);
      speechRef.current = null;
    };

    // 재생 시작
    speechRef.current = utterance;
    window.speechSynthesis.speak(utterance);
  };

  // ===== 음성 정지 =====
  const stopSpeaking = () => {
    if (speechRef.current) {
      window.speechSynthesis.cancel();
      speechRef.current = null;
    }
    setIsQuestionPlaying(false);
    setIsAnswerPlaying(false);
  };

  // ===== 컴포넌트 언마운트 시 음성 정리 =====
  React.useEffect(() => {
    return () => {
      if (speechRef.current) {
        window.speechSynthesis.cancel();
      }
    };
  }, []);

  // ===== 질문 렌더링 =====
  const renderQuestion = () => (
    <div className="question-section">
      <div className="section-header">
        <div className="header-left">
          <h3 className="section-title">
            <span className="section-icon">❓</span>
            Question {questionNumber}
          </h3>
          <span className="question-progress">{questionNumber} of {totalQuestions}</span>
        </div>
        <div className="audio-controls">
          <button
            className={`audio-button ${isQuestionPlaying ? 'playing' : ''}`}
           onClick={() => isQuestionPlaying ? stopSpeaking() : speakText(question.question, true)}
           title={isQuestionPlaying ? 'Stop audio' : 'Play question'}
         >
           <span className="audio-icon">
             {isQuestionPlaying ? '⏹️' : '🔊'}
           </span>
           <span className="audio-label">
             {isQuestionPlaying ? 'Stop' : 'Listen'}
           </span>
         </button>
       </div>
     </div>

     <div className="question-content">
       <div className="question-text">
         {question.question}
       </div>
       
       {question.category && (
         <div className="question-meta">
           <span className="category-tag">
             <span className="tag-icon">🏷️</span>
             {question.category}
           </span>
         </div>
       )}
     </div>
   </div>
 );

 // ===== 모범답안 렌더링 =====
 const renderModelAnswer = () => (
   <div className="model-answer-section">
     <div className="section-header">
       <div className="header-left">
         <h3 className="section-title">
           <span className="section-icon">💡</span>
           Model Answer
         </h3>
         <span className="answer-badge">Reference Answer</span>
       </div>
       <div className="audio-controls">
         <button
           className={`audio-button ${isAnswerPlaying ? 'playing' : ''}`}
           onClick={() => isAnswerPlaying ? stopSpeaking() : speakText(question.model_answer, false)}
           title={isAnswerPlaying ? 'Stop audio' : 'Play model answer'}
         >
           <span className="audio-icon">
             {isAnswerPlaying ? '⏹️' : '🔊'}
           </span>
           <span className="audio-label">
             {isAnswerPlaying ? 'Stop' : 'Listen'}
           </span>
         </button>
       </div>
     </div>

     <div className="answer-content">
       <div className="answer-text">
         {question.model_answer}
       </div>
       
       <div className="answer-tips">
         <div className="tip-item">
           <span className="tip-icon">💭</span>
           <span className="tip-text">Use this as a reference for structure and content</span>
         </div>
         <div className="tip-item">
           <span className="tip-icon">🎯</span>
           <span className="tip-text">Practice expressing similar ideas in your own words</span>
         </div>
       </div>
     </div>
   </div>
 );

 return (
   <div className="fixed-model-card">
     {/* 카드 헤더 */}
     <div className="card-header">
       <div className="card-title">
         <span className="title-icon">🎯</span>
         <span className="title-text">Training Question</span>
       </div>
       <div className="card-meta">
         <span className="meta-item">
           <span className="meta-icon">📝</span>
           {question.part}
         </span>
         <span className="meta-item">
           <span className="meta-icon">⭐</span>
           {question.level}
         </span>
       </div>
     </div>

     {/* 질문 섹션 */}
     {renderQuestion()}

     {/* 모범답안 토글 버튼 */}
     <div className="model-answer-toggle">
       {canShowModelAnswer ? (
         <button
           className={`toggle-button ${showModelAnswer ? 'active' : ''}`}
           onClick={onToggleModelAnswer}
         >
           <span className="toggle-icon">
             {showModelAnswer ? '🙈' : '👁️'}
           </span>
           <span className="toggle-text">
             {showModelAnswer ? 'Hide Model Answer' : 'Show Model Answer'}
           </span>
           <span className="toggle-arrow">
             {showModelAnswer ? '▲' : '▼'}
           </span>
         </button>
       ) : (
         <div className="no-model-answer">
           <span className="no-answer-icon">🔒</span>
           <span className="no-answer-text">Model answer not available for this question</span>
         </div>
       )}
     </div>

     {/* 모범답안 섹션 (조건부 렌더링) */}
     {showModelAnswer && canShowModelAnswer && (
       <div className="model-answer-container">
         {renderModelAnswer()}
       </div>
     )}

     {/* 카드 푸터 */}
     <div className="card-footer">
       <div className="footer-info">
         <span className="info-item">
           <span className="info-icon">🎙️</span>
           Record your answer above
         </span>
         <span className="info-item">
           <span className="info-icon">🔄</span>
           Compare with model answer
         </span>
       </div>
     </div>
   </div>
 );
};

export default FixedModelCard;